import{_ as e,o as t,c as r,ag as o}from"./chunks/framework.C9sp7nFj.js";const _=JSON.parse('{"title":"日本签证指南","description":"日本旅游签证申请条件、材料和流程","frontmatter":{"title":"日本签证指南","description":"日本旅游签证申请条件、材料和流程"},"headers":[],"relativePath":"knowledge/visa/japan.md","filePath":"knowledge/visa/japan.md","lastUpdated":null}'),n={name:"knowledge/visa/japan.md"};function i(l,a,d,s,h,p){return t(),r("div",null,[...a[0]||(a[0]=[o('<h1 id="日本签证指南" tabindex="-1">日本签证指南 <a class="header-anchor" href="#日本签证指南" aria-label="Permalink to &quot;日本签证指南&quot;">​</a></h1><h2 id="日本签证类型" tabindex="-1">日本签证类型 <a class="header-anchor" href="#日本签证类型" aria-label="Permalink to &quot;日本签证类型&quot;">​</a></h2><p>日本旅游签证分为单次、三年多次和五年多次三种。多次签证适合频繁赴日的旅行者。</p><h2 id="申请条件" tabindex="-1">申请条件 <a class="header-anchor" href="#申请条件" aria-label="Permalink to &quot;申请条件&quot;">​</a></h2><p>申请人需持有有效护照，有稳定的工作和收入，并提供相应的资产证明。不同领区的要求略有差异。</p><h2 id="所需材料" tabindex="-1">所需材料 <a class="header-anchor" href="#所需材料" aria-label="Permalink to &quot;所需材料&quot;">​</a></h2><p>包括护照原件、申请表、照片、在职证明、银行流水、房产证或车辆登记证等资产证明。</p><h2 id="申请流程" tabindex="-1">申请流程 <a class="header-anchor" href="#申请流程" aria-label="Permalink to &quot;申请流程&quot;">​</a></h2><p>日本签证需通过指定代办机构递交，个人无法直接向使领馆申请。通常需要5-7个工作日处理。</p><h2 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to &quot;注意事项&quot;">​</a></h2><p>签证有效期和停留期需区分清楚。多次签证首次入境通常有行程要求，需遵守规定。</p>',11)])])}const u=e(n,[["render",i]]);export{_ as __pageData,u as default};
